/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Implements the NotificationAdapter interface with:
 * - URL validation
 * - JSON payload formatting
 * - Priority-based handling
 * - Configurable behavior (for testing vs production use)
 *
 * In dev/test mode, webhook deliveries are stored in memory. A production
 * implementation would make real HTTP POST requests to the configured URL.
 */

import type { NotificationPayload } from '../models/notification.js';
import type { NotificationAdapter, NotificationDeliveryResult } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

/**
 * A record of a webhook delivery that was "sent" (logged in dev/test).
 */
export interface SentWebhook {
  url: string;
  payload: WebhookPayloadBody;
  sentAt: Date;
}

/**
 * The JSON body sent to the webhook URL.
 */
export interface WebhookPayloadBody {
  event: string;
  recipient: string;
  subject: string;
  body: string;
  priority: string;
  metadata?: Record<string, unknown>;
  timestamp: string;
}

/**
 * Configuration for the WebhookAdapter.
 */
export interface WebhookAdapterConfig {
  url: string;
  secret?: string;
}

/**
 * Validate that a string is a well-formed HTTP(S) URL.
 */
function isValidUrl(url: string): boolean {
  try {
    const parsed = new URL(url);
    return parsed.protocol === 'http:' || parsed.protocol === 'https:';
  } catch {
    return false;
  }
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private sentWebhooks: SentWebhook[] = [];
  private config: WebhookAdapterConfig;

  constructor(config: WebhookAdapterConfig) {
    this.config = { ...config };
  }

  /**
   * Send a notification via webhook (HTTP POST).
   *
   * Validates the configured URL, formats the notification as JSON,
   * and stores the delivery record. Returns a delivery result
   * indicating success or failure.
   */
  async send(payload: NotificationPayload): Promise<NotificationDeliveryResult> {
    if (!this.config.url || !isValidUrl(this.config.url)) {
      this.logger.error(`Invalid webhook URL: ${this.config.url}`);
      return {
        success: false,
        channel: 'webhook',
        error: `Invalid webhook URL: ${this.config.url}`,
      };
    }

    try {
      const webhookPayload = this.formatPayload(payload);

      this.logger.info(
        `Sending ${payload.priority}-priority webhook to ${this.config.url}: ${payload.subject}`,
      );

      const record: SentWebhook = {
        url: this.config.url,
        payload: webhookPayload,
        sentAt: new Date(),
      };

      this.sentWebhooks.push(record);

      return {
        success: true,
        channel: 'webhook',
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error';
      this.logger.error(`Failed to send webhook to ${this.config.url}: ${message}`);
      return {
        success: false,
        channel: 'webhook',
        error: message,
      };
    }
  }

  /**
   * Format a notification payload into the JSON body for the webhook POST.
   */
  formatPayload(payload: NotificationPayload): WebhookPayloadBody {
    return {
      event: payload.type,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      priority: payload.priority,
      metadata: payload.metadata,
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * Get the adapter configuration (read-only copy).
   */
  getConfig(): Readonly<WebhookAdapterConfig> {
    return { ...this.config };
  }

  /**
   * Get all sent webhooks (useful for testing).
   */
  getSentWebhooks(): SentWebhook[] {
    return [...this.sentWebhooks];
  }

  /**
   * Clear sent webhook history (useful for testing).
   */
  clearSentWebhooks(): void {
    this.sentWebhooks = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: 'alice@example.com',
    subject: 'Test Subject',
    body: 'Test body content',
    type: 'order_confirmation',
    channel: 'webhook',
    priority: 'normal',
    metadata: { orderId: 'order-1' },
    ...overrides,
  };
}

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;

  beforeEach(() => {
    adapter = new WebhookAdapter({ url: 'https://hooks.example.com/notify' });
  });

  describe('send', () => {
    it('should successfully send a valid webhook', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.channel).toBe('webhook');
      expect(result.error).toBeUndefined();
    });

    it('should store sent webhook with correct fields', async () => {
      await adapter.send(makePayload());

      const webhooks = adapter.getSentWebhooks();
      expect(webhooks).toHaveLength(1);
      expect(webhooks[0]?.url).toBe('https://hooks.example.com/notify');
      expect(webhooks[0]?.payload.recipient).toBe('alice@example.com');
      expect(webhooks[0]?.payload.subject).toBe('Test Subject');
      expect(webhooks[0]?.payload.body).toBe('Test body content');
      expect(webhooks[0]?.payload.event).toBe('order_confirmation');
      expect(webhooks[0]?.payload.priority).toBe('normal');
      expect(webhooks[0]?.payload.metadata).toEqual({ orderId: 'order-1' });
      expect(webhooks[0]?.sentAt).toBeInstanceOf(Date);
    });

    it('should fail for invalid webhook URL', async () => {
      const badAdapter = new WebhookAdapter({ url: 'not-a-url' });
      const result = await badAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.channel).toBe('webhook');
      expect(result.error).toContain('Invalid webhook URL');
    });

    it('should fail for empty URL', async () => {
      const badAdapter = new WebhookAdapter({ url: '' });
      const result = await badAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
    });

    it('should not store webhook on validation failure', async () => {
      const badAdapter = new WebhookAdapter({ url: 'bad' });
      await badAdapter.send(makePayload());

      expect(badAdapter.getSentWebhooks()).toHaveLength(0);
    });

    it('should handle multiple sends', async () => {
      await adapter.send(makePayload({ recipient: 'alice@example.com' }));
      await adapter.send(makePayload({ recipient: 'bob@example.com' }));

      expect(adapter.getSentWebhooks()).toHaveLength(2);
    });

    it('should include priority in sent webhook payload', async () => {
      await adapter.send(makePayload({ priority: 'high' }));

      expect(adapter.getSentWebhooks()[0]?.payload.priority).toBe('high');
    });

    it('should reject non-HTTP protocols', async () => {
      const ftpAdapter = new WebhookAdapter({ url: 'ftp://example.com/hook' });
      const result = await ftpAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
    });
  });

  describe('payload formatting', () => {
    it('should format payload with all fields', () => {
      const formatted = adapter.formatPayload(makePayload());

      expect(formatted.event).toBe('order_confirmation');
      expect(formatted.recipient).toBe('alice@example.com');
      expect(formatted.subject).toBe('Test Subject');
      expect(formatted.body).toBe('Test body content');
      expect(formatted.priority).toBe('normal');
      expect(formatted.metadata).toEqual({ orderId: 'order-1' });
      expect(formatted.timestamp).toBeDefined();
    });

    it('should include ISO timestamp', () => {
      const formatted = adapter.formatPayload(makePayload());

      // Verify it's a valid ISO date string
      expect(() => new Date(formatted.timestamp)).not.toThrow();
      expect(new Date(formatted.timestamp).toISOString()).toBe(formatted.timestamp);
    });

    it('should map notification type to event field', () => {
      const formatted = adapter.formatPayload(
        makePayload({ type: 'order_status_update' }),
      );

      expect(formatted.event).toBe('order_status_update');
    });

    it('should handle payload without metadata', () => {
      const formatted = adapter.formatPayload(
        makePayload({ metadata: undefined }),
      );

      expect(formatted.metadata).toBeUndefined();
    });
  });

  describe('configuration', () => {
    it('should store the configured URL', () => {
      const config = adapter.getConfig();
      expect(config.url).toBe('https://hooks.example.com/notify');
    });

    it('should accept custom config with secret', () => {
      const custom = new WebhookAdapter({
        url: 'https://api.example.com/webhook',
        secret: 'my-secret',
      });

      const config = custom.getConfig();
      expect(config.url).toBe('https://api.example.com/webhook');
      expect(config.secret).toBe('my-secret');
    });

    it('should return defensive copy of config', () => {
      const config1 = adapter.getConfig();
      const config2 = adapter.getConfig();
      expect(config1).not.toBe(config2);
      expect(config1).toEqual(config2);
    });
  });

  describe('webhook management', () => {
    it('should return defensive copy of sent webhooks', async () => {
      await adapter.send(makePayload());

      const webhooks1 = adapter.getSentWebhooks();
      const webhooks2 = adapter.getSentWebhooks();
      expect(webhooks1).not.toBe(webhooks2);
      expect(webhooks1).toEqual(webhooks2);
    });

    it('should clear sent webhooks', async () => {
      await adapter.send(makePayload());
      adapter.clearSentWebhooks();

      expect(adapter.getSentWebhooks()).toHaveLength(0);
    });
  });
});

